    33  // Determine collection set candidates (from marking): For all regions determine
    34  // whether they should be a collection set candidate, calculate their efficiency,
    35  // sort and put them into the candidates.
    36  // Threads calculate the GC efficiency of the regions they get to process, and
    37  // put them into some work area without sorting. At the end that array is sorted and
    38  // moved to the destination.
    39  class G1BuildCandidateRegionsTask : public WorkerTask {
    40
    41    using CandidateInfo = G1CollectionSetCandidateInfo;
    42
    43    // Work area for building the set of collection set candidates. Contains references
    44    // to heap regions with their GC efficiencies calculated. To reduce contention
    45    // on claiming array elements, worker threads claim parts of this array in chunks;
    46    // Array elements may be null as threads might not get enough regions to fill
    47    // up their chunks completely.
    48    // Final sorting will remove them.
    49    class G1BuildCandidateArray : public StackObj {
    50
    51      uint const _max_size;
    52      uint const _chunk_size;
    53
    54      CandidateInfo* _data;
    55
    56      uint volatile _cur_claim_idx;
    57
    58      // Calculates the maximum array size that will be used.
    59      static uint required_array_size(uint num_regions, uint chunk_size, uint num_workers) {
    60        uint const max_waste = num_workers * chunk_size;
    61        // The array should be aligned with respect to chunk_size.
    62        uint const aligned_num_regions = ((num_regions + chunk_size - 1) / chunk_size) * chunk_size;
    63
    64        return aligned_num_regions + max_waste;
    65      }
    66
    67    public:
    68      G1BuildCandidateArray(uint max_num_regions, uint chunk_size, uint num_workers) :
    69        _max_size(required_array_size(max_num_regions, chunk_size, num_workers)),
    70        _chunk_size(chunk_size),
    71        _data(NEW_C_HEAP_ARRAY(CandidateInfo, _max_size, mtGC)),
    72        _cur_claim_idx(0) {
    73        for (uint i = 0; i < _max_size; i++) {
    74          _data[i] = CandidateInfo();
    75        }
    76      }
    77
    78      ~G1BuildCandidateArray() {
    79        FREE_C_HEAP_ARRAY(CandidateInfo, _data);
    80      }
    81
    82      // Claim a new chunk, returning its bounds [from, to[.
    83      void claim_chunk(uint& from, uint& to) {
    84        uint result = Atomic::add(&_cur_claim_idx, _chunk_size);
    85        assert(_max_size > result - 1,
    86               "Array too small, is %u should be %u with chunk size %u.",
    87               _max_size, result, _chunk_size);
    88        from = result - _chunk_size;
    89        to = result;
    90      }
    91
    92      // Set element in array.
    93      void set(uint idx, G1HeapRegion* hr) {
    94        assert(idx < _max_size, "Index %u out of bounds %u", idx, _max_size);
    95        assert(_data[idx]._r == nullptr, "Value must not have been set.");
    96        _data[idx] = CandidateInfo(hr);
    97      }
    98
    99      void sort_by_reclaimable_bytes() {
   100        if (_cur_claim_idx == 0) {
   101          return;
   102        }
   103        for (uint i = _cur_claim_idx; i < _max_size; i++) {
   104          assert(_data[i]._r == nullptr, "must be");
   105        }
   106        qsort(_data, _cur_claim_idx, sizeof(_data[0]), (_sort_Fn)G1CSetCandidateGroup::compare_reclaimble_bytes);
   107        for (uint i = _cur_claim_idx; i < _max_size; i++) {
   108          assert(_data[i]._r == nullptr, "must be");
   109        }
   110      }
   111
   112      CandidateInfo* array() const { return _data; }
   113    };
   114
   115    // Per-region closure. In addition to determining whether a region should be
   116    // added to the candidates, and calculating those regions' gc efficiencies, also
   117    // gather additional statistics.
   118    class G1BuildCandidateRegionsClosure : public G1HeapRegionClosure {
   119      G1BuildCandidateArray* _array;
   120
   121      uint _cur_chunk_idx;
   122      uint _cur_chunk_end;
   123
   124      uint _regions_added;
   125
   126      void add_region(G1HeapRegion* hr) {
   127        if (_cur_chunk_idx == _cur_chunk_end) {
   128          _array->claim_chunk(_cur_chunk_idx, _cur_chunk_end);
   129        }
   130        assert(_cur_chunk_idx < _cur_chunk_end, "Must be");
   131
   132        _array->set(_cur_chunk_idx, hr);
   133        _cur_chunk_idx++;
   134
   135        _regions_added++;
   136      }
   137
   138    public:
   139      G1BuildCandidateRegionsClosure(G1BuildCandidateArray* array) :
   140        _array(array),
   141        _cur_chunk_idx(0),
   142        _cur_chunk_end(0),
   143        _regions_added(0) { }
   144
   145      bool do_heap_region(G1HeapRegion* r) {
   146        // Candidates from marking are always old; also keep regions that are already
   147        // collection set candidates (some retained regions) in that list.
   148        if (!r->is_old() || r->is_collection_set_candidate()) {
   149          // Keep remembered sets and everything for these regions.
   150          return false;
   151        }
   152
   153        // Can not add a region without a remembered set to the candidates.
   154        if (!r->rem_set()->is_tracked()) {
   155          return false;
   156        }
   157
   158        // Skip any region that is currently used as an old GC alloc region. We should
   159        // not consider those for collection before we fill them up as the effective
   160        // gain from them is small. I.e. we only actually reclaim from the filled part,
   161        // as the remainder is still eligible for allocation. These objects are also
   162        // likely to have already survived a few collections, so they might be longer
   163        // lived anyway.
   164        // Otherwise the Old region must satisfy the liveness condition.
   165        bool should_add = !G1CollectedHeap::heap()->is_old_gc_alloc_region(r) &&
   166                          G1CollectionSetChooser::region_occupancy_low_enough_for_evac(r->live_bytes());
   167        if (should_add) {
   168          add_region(r);
   169        } else {
   170          r->rem_set()->clear(true /* only_cardset */);
   171        }
   172        return false;
   173      }
   174
   175      uint regions_added() const { return _regions_added; }
   176    };
   177
   178    G1CollectedHeap* _g1h;
   179    G1HeapRegionClaimer _hrclaimer;
   180
   181    uint volatile _num_regions_added;
   182
   183    G1BuildCandidateArray _result;
   184
   185    void update_totals(uint num_regions) {
   186      if (num_regions > 0) {
   187        Atomic::add(&_num_regions_added, num_regions);
   188      }
   189    }
   190
   191    // Early prune (remove) regions meeting the G1HeapWastePercent criteria. That
   192    // is, either until only the minimum amount of old collection set regions are
   193    // available (for forward progress in evacuation) or the waste accumulated by the
   194    // removed regions is above the maximum allowed waste.
   195    // Updates number of candidates and reclaimable bytes given.
   196    void prune(CandidateInfo* data) {
   197      G1Policy* p = G1CollectedHeap::heap()->policy();
   198
   199      uint num_candidates = Atomic::load(&_num_regions_added);
   200
   201      uint min_old_cset_length = p->calc_min_old_cset_length(num_candidates);
   202      uint num_pruned = 0;
   203      size_t wasted_bytes = 0;
   204
   205      if (min_old_cset_length >= num_candidates) {
   206        // We take all of the candidate regions to provide some forward progress.
   207        return;
   208      }
   209
   210      size_t allowed_waste = p->allowed_waste_in_collection_set();
   211      uint max_to_prune = num_candidates - min_old_cset_length;
   212
   213      while (true) {
   214        G1HeapRegion* r = data[num_candidates - num_pruned - 1]._r;
   215        size_t const reclaimable = r->reclaimable_bytes();
   216        if (num_pruned >= max_to_prune ||
   217            wasted_bytes + reclaimable > allowed_waste) {
   218          break;
   219        }
   220        r->rem_set()->clear(true /* cardset_only */);
   221
   222        wasted_bytes += reclaimable;
   223        num_pruned++;
   224      }
   225
   226      log_debug(gc, ergo, cset)("Pruned %u regions out of %u, leaving %zu bytes waste (allowed %zu)",
   227                                num_pruned,
   228                                num_candidates,
   229                                wasted_bytes,
   230                                allowed_waste);
   231
   232      Atomic::sub(&_num_regions_added, num_pruned, memory_order_relaxed);
   233    }
   234
   235  public:
   236    G1BuildCandidateRegionsTask(uint max_num_regions, uint chunk_size, uint num_workers) :
   237      WorkerTask("G1 Build Candidate Regions"),
   238      _g1h(G1CollectedHeap::heap()),
   239      _hrclaimer(num_workers),
   240      _num_regions_added(0),
   241      _result(max_num_regions, chunk_size, num_workers) { }
   242
   243    void work(uint worker_id) {
   244      G1BuildCandidateRegionsClosure cl(&_result);
   245      _g1h->heap_region_par_iterate_from_worker_offset(&cl, &_hrclaimer, worker_id);
   246      update_totals(cl.regions_added());
   247    }
   248
   249    void sort_and_prune_into(G1CollectionSetCandidates* candidates) {
   250      _result.sort_by_reclaimable_bytes();
   251      prune(_result.array());
   252      candidates->set_candidates_from_marking(_result.array(),
   253                                              _num_regions_added);
   254    }
   255  };
   256
   257  uint G1CollectionSetChooser::calculate_work_chunk_size(uint num_workers, uint num_regions) {
   258    assert(num_workers > 0, "Active gc workers should be greater than 0");
   259    return MAX2(num_regions / num_workers, 1U);
   260  }
   261
   262  void G1CollectionSetChooser::build(WorkerThreads* workers, uint max_num_regions, G1CollectionSetCandidates* candidates) {
   263    uint num_workers = workers->active_workers();
   264    uint chunk_size = calculate_work_chunk_size(num_workers, max_num_regions);
   265
   266    G1BuildCandidateRegionsTask cl(max_num_regions, chunk_size, num_workers);
   267    workers->run_task(&cl, num_workers);
   268
   269    cl.sort_and_prune_into(candidates);
   270    candidates->verify();
   271  }

