    99  size_t G1AdaptiveIHOPControl::actual_target_threshold() const {
   100    guarantee(_target_occupancy > 0, "Target occupancy still not updated yet.");
   101    // The actual target threshold takes the heap reserve and the expected waste in
   102    // free space  into account.
   103    // _heap_reserve is that part of the total heap capacity that is reserved for
   104    // eventual promotion failure.
   105    // _heap_waste is the amount of space will never be reclaimed in any
   106    // heap, so can not be used for allocation during marking and must always be
   107    // considered.
   108
   109    double safe_total_heap_percentage = MIN2((double)(_heap_reserve_percent + _heap_waste_percent), 100.0);
   110
   111    return (size_t)MIN2(
   112      G1CollectedHeap::heap()->max_capacity() * (100.0 - safe_total_heap_percentage) / 100.0,
   113      _target_occupancy * (100.0 - _heap_waste_percent) / 100.0
   114      );
   115  }
   116
   117  double G1AdaptiveIHOPControl::predict(TruncatedSeq const* seq) const {
   118    return _predictor->predict_zero_bounded(seq);
   119  }
   120
   121  bool G1AdaptiveIHOPControl::have_enough_data_for_prediction() const {
   122    return ((size_t)_marking_times_s.num() >= G1AdaptiveIHOPNumInitialSamples) &&
   123           ((size_t)_allocation_rate_s.num() >= G1AdaptiveIHOPNumInitialSamples);
   124  }
   125
   126  size_t G1AdaptiveIHOPControl::get_conc_mark_start_threshold() {
   127    if (have_enough_data_for_prediction()) {
   128      double pred_marking_time = predict(&_marking_times_s);
   129      double pred_promotion_rate = predict(&_allocation_rate_s);
   130      size_t pred_promotion_size = (size_t)(pred_marking_time * pred_promotion_rate);
   131
   132      size_t predicted_needed_bytes_during_marking =
   133        pred_promotion_size +
   134        // In reality we would need the maximum size of the young gen during
   135        // marking. This is a conservative estimate.
   136        _last_unrestrained_young_size;
   137
   138      size_t internal_threshold = actual_target_threshold();
   139      size_t predicted_initiating_threshold = predicted_needed_bytes_during_marking < internal_threshold ?
   140                                              internal_threshold - predicted_needed_bytes_during_marking :
   141                                              0;
   142      return predicted_initiating_threshold;
   143    } else {
   144      // Use the initial value.
   145      return (size_t)(_initial_ihop_percent * _target_occupancy / 100.0);
   146    }
   147  }
   148
   149  double G1AdaptiveIHOPControl::last_mutator_period_old_allocation_rate() const {
   150    assert(_last_allocation_time_s > 0, "This should not be called when the last GC is full");
   151
   152    return _old_gen_alloc_tracker->last_period_old_gen_growth() / _last_allocation_time_s;
   153  }
